<span class="line"><span style="color:#383A42;">  &lt;</span><span style="color:#E45649;">p</span><span style="color:#383A42;">&gt;Описание/p&gt;&lt;/</span><span style="color:#E45649;">p</span><span style="color:#383A42;">&gt;</span></span>
